import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const WelcomePage = () => {
  const [stage, setStage] = useState('tracing'); // tracing -> highlight -> main

  useEffect(() => {
    // Sequence: Trace (2s) -> Highlight (1s) -> Main Site
    const timer1 = setTimeout(() => setStage('highlight'), 2000);
    const timer2 = setTimeout(() => setStage('main'), 3200);
    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  const featuresRow1 = [
    { title: 'Course Curator', desc: 'AI picks the single best video for your concept.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions with explanations.' },
    { title: 'Notes Generator', desc: 'Live summaries and key concepts.' },
    { title: 'Course Curator', desc: 'AI picks the single best video.' },
  ];

  const featuresRow2 = [
    { title: 'Revision Scheduler', desc: 'Smart reminders for better retention.' },
    { title: 'Update Acknowledger', desc: 'Stay updated within 48 hours.' },
    { title: 'Premium Features', desc: 'Unlock full learning power.' },
    { title: 'Revision Scheduler', desc: 'Smart reminders.' },
  ];

  // SVG Drawing Variants
  const draw = {
    hidden: { pathLength: 0, opacity: 0 },
    visible: {
      pathLength: 1,
      opacity: 1,
      transition: { pathLength: { type: "spring", duration: 2, bounce: 0 }, opacity: { duration: 0.01 } }
    }
  };

  return (
    <div className="min-h-screen bg-white text-[#0B3954] overflow-x-hidden font-serif">

      {/* 1. LOGO ANIMATION STAGE */}
      <AnimatePresence>
        {(stage === 'tracing' || stage === 'highlight') && (
          <motion.div
            key="intro-loader"
            className="fixed inset-0 flex items-center justify-center bg-white z-50"
            exit={{ opacity: 0, scale: 1.1, filter: "blur(10px)" }}
            transition={{ duration: 0.8 }}
          >
            <div className="relative w-64 h-64">
              <svg viewBox="0 0 100 100" className="w-full h-full">
                {/* Neural Network Tracing */}
                <motion.path
                  d="M30,50 Q20,20 50,15 T80,50 T50,85 T20,50" // Simplified Brain Outline
                  fill="none"
                  stroke="#0B3954"
                  strokeWidth="1.5"
                  variants={draw}
                  initial="hidden"
                  animate="visible"
                />
                {/* Internal Connections (Neural Dots) */}
                <motion.circle cx="35" cy="40" r="2" fill="#0B3954" initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.5 }} />
                <motion.circle cx="65" cy="35" r="2" fill="#0B3954" initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.8 }} />
                <motion.circle cx="50" cy="70" r="2" fill="#0B3954" initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1.1 }} />

                {/* Play Button - Highlighted in stage 'highlight' */}
                <motion.path
                  d="M42,40 L62,50 L42,60 Z"
                  fill={stage === 'highlight' ? "#0B3954" : "none"}
                  stroke="#0B3954"
                  strokeWidth="2"
                  initial={{ opacity: 0 }}
                  animate={{ 
                    opacity: 1, 
                    scale: stage === 'highlight' ? [1, 1.2, 1] : 1 
                  }}
                  transition={{ duration: 0.5 }}
                />

                {/* The Star Sparkle */}
                <motion.path
                  d="M75,30 L77,35 L82,37 L77,39 L75,44 L73,39 L68,37 L73,35 Z"
                  fill="#0B3954"
                  initial={{ opacity: 0, scale: 0 }}
                  animate={{ opacity: stage === 'highlight' ? 1 : 0, scale: stage === 'highlight' ? 1 : 0 }}
                />
              </svg>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* 2. MAIN CONTENT */}
      {stage === 'main' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 1 }}>

          {/* HEADER - REFINED SIZE */}
          <header className="fixed top-0 left-0 right-0 h-24 flex items-center justify-between px-10 z-40 bg-white/70 backdrop-blur-md border-b border-gray-100">
            <div className="flex items-center"> 
               {/* Small sized logo for navigation */}
               <div className="w-12 h-12 text-[#0B3954]">
                  <svg viewBox="0 0 100 100" fill="currentColor">
                    <path d="M30,50 Q20,20 50,15 T80,50 T50,85 T20,50 M42,40 L62,50 L42,60 Z" />
                  </svg>
               </div>
               <span className="ml-3 text-2xl font-bold tracking-tighter">CourseCraft</span>
            </div>

            <div className="flex items-center space-x-8">
              <button className="text-xs font-bold tracking-widest text-[#0B3954] hover:opacity-50 transition-opacity">LOG IN</button>
              <button className="px-8 py-3 bg-[#0B3954] text-white rounded-full text-xs font-bold tracking-widest shadow-lg hover:bg-[#082d42] transition-all">
                SIGN UP
              </button>
            </div>
          </header>

          {/* HERO */}
          <section className="h-screen flex flex-col items-center justify-center text-center px-6">
            <motion.div initial={{ y: 30, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.2 }}>
              <h1 className="text-6xl md:text-9xl leading-tight text-black">
                Welcome to <br />
                <span className="italic font-light text-[#0B3954]">CourseCraft</span>
              </h1>
              <p className="mt-8 text-lg md:text-xl tracking-[0.4em] uppercase text-gray-400 font-light">
                Skip the scroll. <span className="text-[#0B3954] font-semibold">Learn the goal</span>
              </p>
            </motion.div>
          </section>

          {/* FEATURES SECTION (Simplified for brevity) */}
          <section className="py-32 bg-[#0B3954] text-white">
            <div className="px-10 mb-16">
              <h2 className="text-5xl italic">The smarter way to learn.</h2>
            </div>
            <div className="flex overflow-hidden group">
               <motion.div 
                className="flex space-x-8 px-10"
                animate={{ x: [0, -1000] }}
                transition={{ duration: 30, repeat: Infinity, ease: "linear" }}
               >
                 {featuresRow1.concat(featuresRow1).map((f, i) => (
                   <div key={i} className="min-w-[400px] p-10 border border-white/20 rounded-3xl bg-white/5">
                      <h3 className="text-2xl font-bold mb-2">{f.title}</h3>
                      <p className="text-white/50">{f.desc}</p>
                   </div>
                 ))}
               </motion.div>
            </div>
          </section>

          <footer className="py-20 flex flex-col items-center justify-center bg-white">
             <p className="text-[10px] tracking-[0.5em] text-gray-400 uppercase">© 2026 CourseCraft AI</p>
          </footer>
        </motion.div>
      )}
    </div>
  );
};

export default WelcomePage;
